func main() {
	// Create a new Prometheus registry.
	registry := prometheus.NewRegistry()

	// Register the custom metrics with the registry.
	userMetrics := prometheus.NewCounterVec(prometheus.Opts{
		Name: "users",
	}, []string{"username"})
	requestMetrics := prometheus.NewCounterVec(prometheus.Opts{
		Name: "requests",
	}, []string{"method", "path", "status"})
	registry.MustRegister(userMetrics)
	registry.MustRegister(requestMetrics)

	// Create a new HTTP server and configure it to use the Prometheus registry.
	httpServer := &http.Server{
		Addr: ":8080",
	}
	httpServer.Handler = prometheus.InstrumentHandlerFunc(registry, http.DefaultServeMux)

	// Start the HTTP server and serve requests.
	fmt.Println("Starting HTTP server on :8080")
	if err := httpServer.ListenAndServe(); err != nil {
		fmt.Printf("Error starting HTTP server: %s\n", err)
	}
}